import{_ as i,o as s,c as l,ag as e}from"./chunks/framework.DGzMGr_a.js";const u=JSON.parse('{"title":"DNS 解析过程与优化","description":"","frontmatter":{"title":"DNS 解析过程与优化","difficulty":"medium","tags":["DNS","网络优化","CDN","DNS 劫持"],"estimate":25},"headers":[],"relativePath":"domains/browser/qa/qa-30-dns-resolution-optimization.md","filePath":"domains/browser/qa/qa-30-dns-resolution-optimization.md","lastUpdated":1783504823000}'),t={name:"domains/browser/qa/qa-30-dns-resolution-optimization.md"};function n(r,a,o,h,d,p){return s(),l("div",null,[...a[0]||(a[0]=[e(`<h1 id="问答-30-进阶-dns-解析过程与优化" tabindex="-1">问答 30（进阶）：DNS 解析过程与优化 <a class="header-anchor" href="#问答-30-进阶-dns-解析过程与优化" aria-label="Permalink to &quot;问答 30（进阶）：DNS 解析过程与优化&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>DNS 解析的完整流程是怎样的？递归查询和迭代查询有什么区别？DNS 缓存有哪些层级？有哪些 DNS 优化手段？DNS 劫持是什么？如何防范？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><h3 id="dns-是什么" tabindex="-1">DNS 是什么 <a class="header-anchor" href="#dns-是什么" aria-label="Permalink to &quot;DNS 是什么&quot;">​</a></h3><p>DNS（Domain Name System，域名系统）是互联网的「电话簿」，把人类可读的域名（如 <code>www.example.com</code>）翻译成机器可读的 IP 地址（如 <code>93.184.216.34</code>）。</p><p>没有 DNS，我们上网就得记住一堆数字 IP 地址。</p><hr><h3 id="dns-解析的完整链路" tabindex="-1">DNS 解析的完整链路 <a class="header-anchor" href="#dns-解析的完整链路" aria-label="Permalink to &quot;DNS 解析的完整链路&quot;">​</a></h3><p>当你在浏览器输入 <code>www.example.com</code> 时，DNS 解析会经过这样一条链路：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>浏览器缓存 → 系统缓存（OS）→ 路由器缓存 → ISP DNS（本地域名服务器）→ 根域名服务器 → 顶级域服务器（.com）→ 权威域名服务器（example.com）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>逐层往上查，每一层都可能有缓存，命中就直接返回，不用再往上走。</p><p><strong>详细过程：</strong></p><h4 id="第-1-步-浏览器-dns-缓存" tabindex="-1">第 1 步：浏览器 DNS 缓存 <a class="header-anchor" href="#第-1-步-浏览器-dns-缓存" aria-label="Permalink to &quot;第 1 步：浏览器 DNS 缓存&quot;">​</a></h4><p>浏览器首先检查自己的 DNS 缓存里有没有这个域名的记录。</p><ul><li>Chrome 可以在 <code>chrome://net-internals/#dns</code> 查看</li><li>缓存时间比较短，一般几分钟（Chrome 默认 1 分钟左右）</li><li>命中就直接返回，不发网络请求</li></ul><h4 id="第-2-步-操作系统缓存-hosts-文件-系统缓存" tabindex="-1">第 2 步：操作系统缓存（hosts 文件 + 系统缓存） <a class="header-anchor" href="#第-2-步-操作系统缓存-hosts-文件-系统缓存" aria-label="Permalink to &quot;第 2 步：操作系统缓存（hosts 文件 + 系统缓存）&quot;">​</a></h4><p>浏览器缓存没命中，就调用系统的 DNS 解析函数。</p><ul><li>系统先查自己的 DNS 缓存</li><li>再查本地的 <code>hosts</code> 文件（<code>/etc/hosts</code> 或 <code>C:\\Windows\\System32\\drivers\\etc\\hosts</code>）</li><li>hosts 文件里的域名是手动配置的，优先级很高</li><li>命中就直接返回</li></ul><h4 id="第-3-步-路由器缓存" tabindex="-1">第 3 步：路由器缓存 <a class="header-anchor" href="#第-3-步-路由器缓存" aria-label="Permalink to &quot;第 3 步：路由器缓存&quot;">​</a></h4><p>系统缓存也没命中，就向路由器发 DNS 请求。</p><ul><li>路由器一般也有自己的 DNS 缓存</li><li>家里的路由器通常把 DNS 请求转发给 ISP 的 DNS 服务器</li></ul><h4 id="第-4-步-isp-dns-本地域名服务器-ldns" tabindex="-1">第 4 步：ISP DNS（本地域名服务器 / LDNS） <a class="header-anchor" href="#第-4-步-isp-dns-本地域名服务器-ldns" aria-label="Permalink to &quot;第 4 步：ISP DNS（本地域名服务器 / LDNS）&quot;">​</a></h4><p>ISP（互联网服务提供商，比如联通、电信、移动）的 DNS 服务器。</p><ul><li>这是大多数用户的「默认 DNS 服务器」</li><li>ISP DNS 有大量缓存，大部分常用域名在这里就能命中</li><li>如果没命中，ISP DNS 就开始<strong>递归查询</strong>过程</li></ul><h4 id="第-5-步-根域名服务器-root-dns" tabindex="-1">第 5 步：根域名服务器（Root DNS） <a class="header-anchor" href="#第-5-步-根域名服务器-root-dns" aria-label="Permalink to &quot;第 5 步：根域名服务器（Root DNS）&quot;">​</a></h4><p>ISP DNS 没命中缓存，就向「根域名服务器」查询。</p><ul><li>全球共有 13 组根域名服务器（A 到 M 根）</li><li>根服务器不存具体域名的 IP，它只知道「顶级域服务器」（如 .com、.org）的地址</li><li>根服务器告诉 ISP DNS：「你要查 .com 的域名，去问 .com 的顶级域服务器，地址是 xxx」</li></ul><blockquote><p>注意：13 组根服务器不是 13 台机器，而是 13 个逻辑编号，背后有几千台物理服务器分布在全球（任播技术）。</p></blockquote><h4 id="第-6-步-顶级域服务器-tld-dns" tabindex="-1">第 6 步：顶级域服务器（TLD DNS） <a class="header-anchor" href="#第-6-步-顶级域服务器-tld-dns" aria-label="Permalink to &quot;第 6 步：顶级域服务器（TLD DNS）&quot;">​</a></h4><p>顶级域（Top-Level Domain）服务器，比如 <code>.com</code>、<code>.org</code>、<code>.cn</code>、<code>.net</code>。</p><ul><li>ISP DNS 向 .com 顶级域服务器查询 <code>example.com</code></li><li>顶级域服务器也不知道具体 IP，它知道 <code>example.com</code> 的「权威域名服务器」地址</li><li>顶级域告诉 ISP DNS：「example.com 的权威服务器是 ns1.example.com，地址是 xxx」</li></ul><h4 id="第-7-步-权威域名服务器-authoritative-dns" tabindex="-1">第 7 步：权威域名服务器（Authoritative DNS） <a class="header-anchor" href="#第-7-步-权威域名服务器-authoritative-dns" aria-label="Permalink to &quot;第 7 步：权威域名服务器（Authoritative DNS）&quot;">​</a></h4><p>权威域名服务器是真正存着这个域名所有 DNS 记录的地方。</p><ul><li>ISP DNS 向权威服务器查询 <code>www.example.com</code></li><li>权威服务器返回对应的 IP 地址（A 记录或 AAAA 记录）</li><li>ISP DNS 拿到结果后，缓存起来（缓存时间由 TTL 决定），然后返回给用户</li></ul><hr><h3 id="递归查询-vs-迭代查询" tabindex="-1">递归查询 vs 迭代查询 <a class="header-anchor" href="#递归查询-vs-迭代查询" aria-label="Permalink to &quot;递归查询 vs 迭代查询&quot;">​</a></h3><p>这是 DNS 解析中两个核心概念，很多人搞混。</p><table tabindex="0"><thead><tr><th>查询类型</th><th>谁负责</th><th>怎么做</th><th>结果</th></tr></thead><tbody><tr><td><strong>递归查询</strong></td><td>客户端 → 本地 DNS</td><td>「你帮我查到底，把最终结果给我」</td><td>返回最终的 IP 地址或报错</td></tr><tr><td><strong>迭代查询</strong></td><td>本地 DNS → 根 / TLD / 权威</td><td>「你告诉我下一步该问谁」</td><td>返回下一个服务器的地址</td></tr></tbody></table><p><strong>打个比方：</strong></p><ul><li>递归查询就像你问前台：「帮我找一下张三的电话。」前台帮你一层层找，最后把号码给你。</li><li>迭代查询就像你问路：「请问去天安门怎么走？」路人说：「你去问前面那个交警。」你去问交警，交警说：「坐 1 号线到西单转 4 号线。」你自己一步步找过去。</li></ul><p><strong>实际过程中：</strong></p><ul><li>浏览器 → 系统 → ISP DNS：<strong>递归查询</strong>（用户端只发一次请求，ISP DNS 负责查到底）</li><li>ISP DNS → 根 → TLD → 权威：<strong>迭代查询</strong>（ISP DNS 自己一步步往上问）</li></ul><p>为什么这么设计？</p><ul><li>对用户来说，递归查询简单，只要配一个 DNS 服务器就行</li><li>对 DNS 系统来说，迭代查询减轻了根服务器的压力，根服务器只需要指路，不用帮你查到底</li></ul><hr><h3 id="dns-记录类型" tabindex="-1">DNS 记录类型 <a class="header-anchor" href="#dns-记录类型" aria-label="Permalink to &quot;DNS 记录类型&quot;">​</a></h3><p>常见的 DNS 记录类型：</p><table tabindex="0"><thead><tr><th>记录类型</th><th>全称</th><th>作用</th><th>示例</th></tr></thead><tbody><tr><td><strong>A</strong></td><td>Address</td><td>域名 → IPv4 地址</td><td><code>example.com → 93.184.216.34</code></td></tr><tr><td><strong>AAAA</strong></td><td>IPv6 Address</td><td>域名 → IPv6 地址</td><td><code>example.com → 2606:2800:220:1:248:1893:25c8:1946</code></td></tr><tr><td><strong>CNAME</strong></td><td>Canonical Name</td><td>域名 → 另一个域名（别名）</td><td><code>www.example.com → example.com</code></td></tr><tr><td><strong>MX</strong></td><td>Mail Exchange</td><td>邮件服务器</td><td><code>example.com → mail.example.com</code></td></tr><tr><td><strong>TXT</strong></td><td>Text</td><td>文本记录（验证、SPF 等）</td><td>用于域名所有权验证、反垃圾邮件</td></tr><tr><td><strong>NS</strong></td><td>Name Server</td><td>权威域名服务器</td><td><code>example.com → ns1.example.com</code></td></tr><tr><td><strong>SOA</strong></td><td>Start of Authority</td><td>区域起始授权记录</td><td>标记域名的主权威服务器、序列号等</td></tr><tr><td><strong>PTR</strong></td><td>Pointer</td><td>IP → 域名（反向解析）</td><td><code>1.2.3.4 → server.example.com</code></td></tr><tr><td><strong>SRV</strong></td><td>Service Locator</td><td>服务位置记录</td><td>指明某个服务在哪台机器的哪个端口</td></tr><tr><td><strong>CAA</strong></td><td>Certification Authority Authorization</td><td>允许哪些 CA 签发证书</td><td>防止证书被恶意签发</td></tr></tbody></table><hr><h3 id="dns-优化手段" tabindex="-1">DNS 优化手段 <a class="header-anchor" href="#dns-优化手段" aria-label="Permalink to &quot;DNS 优化手段&quot;">​</a></h3><p>DNS 解析是网络请求的第一步，DNS 慢了整个请求都慢。常见的优化手段：</p><h4 id="_1-dns-预解析-dns-prefetch" tabindex="-1">1. DNS 预解析（dns-prefetch） <a class="header-anchor" href="#_1-dns-预解析-dns-prefetch" aria-label="Permalink to &quot;1. DNS 预解析（dns-prefetch）&quot;">​</a></h4><p>让浏览器在空闲时提前解析页面中可能用到的域名，等真正请求时已经解析好了。</p><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- 告诉浏览器提前解析这些域名 --&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">link</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> rel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dns-prefetch&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;//cdn.example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">link</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> rel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dns-prefetch&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;//api.example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">link</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> rel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dns-prefetch&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;//fonts.googleapis.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>适用场景：</strong></p><ul><li>页面上引用了很多第三方域名的资源（CDN、统计、字体、广告）</li><li>用户后续可能跳转到的域名</li></ul><p><strong>注意：</strong></p><ul><li>不要滥用，预解析太多也会消耗资源</li><li>只给确实会用到的第三方域名加</li><li>Chrome 对用户 hover 的链接也会自动做 dns-prefetch</li></ul><h4 id="_2-减少-dns-查询次数" tabindex="-1">2. 减少 DNS 查询次数 <a class="header-anchor" href="#_2-减少-dns-查询次数" aria-label="Permalink to &quot;2. 减少 DNS 查询次数&quot;">​</a></h4><ul><li>尽量把资源放在同一个域名下（但也要注意 HTTP/1.1 的并发限制）</li><li>用 CDN 合并多个域名</li><li>不要为了「域名分片」搞太多域名（HTTP/2 时代不需要了）</li></ul><h4 id="_3-合理设置-ttl-缓存时间" tabindex="-1">3. 合理设置 TTL（缓存时间） <a class="header-anchor" href="#_3-合理设置-ttl-缓存时间" aria-label="Permalink to &quot;3. 合理设置 TTL（缓存时间）&quot;">​</a></h4><p>DNS 记录的 TTL（Time To Live）决定了 DNS 结果能缓存多久。</p><ul><li><strong>TTL 太长</strong>：IP 变更后生效慢，用户可能访问到旧 IP</li><li><strong>TTL 太短</strong>：DNS 查询频繁，解析慢，权威服务器压力大</li></ul><p><strong>经验值：</strong></p><ul><li>稳定的服务：TTL 设长一点，如 1 小时（3600s）或 1 天（86400s）</li><li>经常变更的服务：TTL 设短一点，如 5 分钟（300s）或 1 分钟（60s）</li><li>变更前先把 TTL 改短，变更完再改长（平滑切换）</li></ul><h4 id="_4-httpdns-http-dns" tabindex="-1">4. HTTPDNS（HTTP DNS） <a class="header-anchor" href="#_4-httpdns-http-dns" aria-label="Permalink to &quot;4. HTTPDNS（HTTP DNS）&quot;">​</a></h4><p>传统 DNS 走 UDP 53 端口，有几个问题：</p><ul><li>运营商可能劫持 DNS，把用户引导到广告页面</li><li>运营商 DNS 可能有缓存污染</li><li>无法根据用户位置智能调度（Local DNS 可能不在用户本地）</li></ul><p><strong>HTTPDNS 的原理：</strong></p><ul><li>不用传统的 DNS 协议，而是通过 HTTP/HTTPS 请求 DNS 解析结果</li><li>客户端直接向 HTTPDNS 服务器发请求，拿到 IP</li><li>绕过了运营商的 Local DNS</li></ul><p><strong>优点：</strong></p><ul><li>防 DNS 劫持（走 HTTP/HTTPS，不容易被篡改）</li><li>更精准的调度（直接拿用户真实 IP 做地理位置判断，CDN 调度更准）</li><li>解析延迟可控（可以预解析、智能缓存）</li></ul><p><strong>缺点：</strong></p><ul><li>需要客户端 SDK 支持（App 端常用，网页端需要 JS 配合）</li><li>有额外的成本（HTTPDNS 服务一般是付费的）</li><li>网页端使用有局限（需要用 JS 动态改请求地址）</li></ul><p><strong>常见厂商：</strong></p><ul><li>阿里云 HTTPDNS</li><li>腾讯云 HTTPDNS</li><li>Cloudflare 1.1.1.1（也有 DoH / DoT）</li></ul><h4 id="_5-使用公共-dns" tabindex="-1">5. 使用公共 DNS <a class="header-anchor" href="#_5-使用公共-dns" aria-label="Permalink to &quot;5. 使用公共 DNS&quot;">​</a></h4><p>如果运营商 DNS 慢或不准，可以改用公共 DNS：</p><ul><li><strong>Google DNS</strong>：<code>8.8.8.8</code> / <code>8.8.4.4</code></li><li><strong>Cloudflare DNS</strong>：<code>1.1.1.1</code> / <code>1.0.0.1</code>（号称全球最快）</li><li><strong>OpenDNS</strong>：<code>208.67.222.222</code></li><li><strong>国内公共 DNS</strong>：114 DNS（<code>114.114.114.114</code>）、阿里 DNS（<code>223.5.5.5</code>）、DNSPod（<code>119.29.29.29</code>）</li></ul><p>但公共 DNS 也不一定更快，取决于你和它的网络距离。</p><h4 id="_6-cdn-智能调度" tabindex="-1">6. CDN 智能调度 <a class="header-anchor" href="#_6-cdn-智能调度" aria-label="Permalink to &quot;6. CDN 智能调度&quot;">​</a></h4><p>CDN（内容分发网络）和 DNS 紧密配合：</p><ul><li>用户请求 CDN 域名时，DNS 返回离用户最近的 CDN 节点 IP</li><li>基于智能 DNS 解析（根据用户地理位置、运营商、节点负载等）</li><li>让用户从最近的节点拿数据，速度更快</li></ul><p><strong>常见调度方式：</strong></p><ul><li>基于地理位置（GeoDNS）：根据用户 IP 所属地区返回最近节点</li><li>基于运营商：返回同运营商的节点（避免跨运营商访问慢）</li><li>基于负载：返回当前负载较低的节点</li><li>基于探测：实时探测各节点质量，返回最优的</li></ul><h4 id="_7-dns-预连接-preconnect" tabindex="-1">7. DNS 预连接（preconnect） <a class="header-anchor" href="#_7-dns-预连接-preconnect" aria-label="Permalink to &quot;7. DNS 预连接（preconnect）&quot;">​</a></h4><p>比 dns-prefetch 更进一步，不仅解析 DNS，还顺便建立 TCP 连接和 TLS 握手：</p><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">link</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> rel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;preconnect&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://api.example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>适合你确定马上就要用的域名。但不要用太多，因为 preconnect 会占用连接资源。</p><hr><h3 id="dns-劫持与防范" tabindex="-1">DNS 劫持与防范 <a class="header-anchor" href="#dns-劫持与防范" aria-label="Permalink to &quot;DNS 劫持与防范&quot;">​</a></h3><p><strong>什么是 DNS 劫持？</strong></p><ul><li>DNS 解析本来应该返回正确的 IP，但被中间的攻击者篡改了</li><li>用户输入的是正确的域名，却被引导到错误的（恶意的）IP 地址</li><li>结果就是：你以为你在访问淘宝，实际上访问的是钓鱼网站</li></ul><p><strong>常见的 DNS 劫持方式：</strong></p><h4 id="_1-本地劫持-篡改-hosts-文件" tabindex="-1">1. 本地劫持（篡改 hosts 文件） <a class="header-anchor" href="#_1-本地劫持-篡改-hosts-文件" aria-label="Permalink to &quot;1. 本地劫持（篡改 hosts 文件）&quot;">​</a></h4><ul><li>恶意软件修改用户电脑的 <code>hosts</code> 文件</li><li>把银行网站的域名指向钓鱼网站的 IP</li><li>因为 hosts 文件优先级最高，直接就被劫持了</li></ul><p><strong>防范：</strong> 安装杀毒软件，不要乱装软件，定期检查 hosts 文件。</p><h4 id="_2-路由器劫持" tabindex="-1">2. 路由器劫持 <a class="header-anchor" href="#_2-路由器劫持" aria-label="Permalink to &quot;2. 路由器劫持&quot;">​</a></h4><ul><li>路由器的 DNS 配置被篡改（比如路由器管理密码太简单，被黑客登录改掉）</li><li>所有连这个路由器的设备都被劫持了</li></ul><p><strong>防范：</strong> 修改路由器默认管理密码，及时升级固件，不要用弱密码。</p><h4 id="_3-运营商-dns-劫持" tabindex="-1">3. 运营商 DNS 劫持 <a class="header-anchor" href="#_3-运营商-dns-劫持" aria-label="Permalink to &quot;3. 运营商 DNS 劫持&quot;">​</a></h4><ul><li>运营商的 DNS 服务器返回错误的结果</li><li>比如你访问一个不存在的域名，运营商给你跳转到它的搜索广告页</li><li>更恶劣的情况：把正常网站跳转到广告页</li></ul><p><strong>防范：</strong> 改用公共 DNS（8.8.8.8、114.114.114.114 等），用 DoH / DoT。</p><h4 id="_4-中间人攻击-mitm" tabindex="-1">4. 中间人攻击（MITM） <a class="header-anchor" href="#_4-中间人攻击-mitm" aria-label="Permalink to &quot;4. 中间人攻击（MITM）&quot;">​</a></h4><ul><li>攻击者在网络中间拦截 DNS 请求和响应，篡改返回结果</li><li>公共 Wi-Fi 环境下更容易发生</li></ul><p><strong>防范：</strong> 使用 DNS 加密技术（DoH / DoT）。</p><hr><h3 id="dns-安全技术" tabindex="-1">DNS 安全技术 <a class="header-anchor" href="#dns-安全技术" aria-label="Permalink to &quot;DNS 安全技术&quot;">​</a></h3><h4 id="_1-doh-dns-over-https" tabindex="-1">1. DoH（DNS over HTTPS） <a class="header-anchor" href="#_1-doh-dns-over-https" aria-label="Permalink to &quot;1. DoH（DNS over HTTPS）&quot;">​</a></h4><ul><li>DNS 查询通过 HTTPS 加密传输</li><li>中间人看不到你查了什么域名，也篡改不了结果</li><li>常见的公共 DNS 都支持：<code>https://1.1.1.1/dns-query</code>、<code>https://dns.google/dns-query</code></li></ul><h4 id="_2-dot-dns-over-tls" tabindex="-1">2. DoT（DNS over TLS） <a class="header-anchor" href="#_2-dot-dns-over-tls" aria-label="Permalink to &quot;2. DoT（DNS over TLS）&quot;">​</a></h4><ul><li>DNS 查询通过 TLS 加密传输</li><li>和 DoH 类似，只是用的是 TLS 协议而不是 HTTPS</li><li>标准端口 853</li></ul><h4 id="_3-dnssec-dns-security-extensions" tabindex="-1">3. DNSSEC（DNS Security Extensions） <a class="header-anchor" href="#_3-dnssec-dns-security-extensions" aria-label="Permalink to &quot;3. DNSSEC（DNS Security Extensions）&quot;">​</a></h4><ul><li>给 DNS 记录加上数字签名</li><li>递归 DNS 服务器可以验证返回结果的真实性和完整性</li><li>防止 DNS 响应被篡改</li><li>但需要域名所有者配置 DNSSEC 记录，普及度还不高</li></ul><h4 id="_4-dnssec-vs-doh-dot" tabindex="-1">4. DNSSEC vs DoH/DoT <a class="header-anchor" href="#_4-dnssec-vs-doh-dot" aria-label="Permalink to &quot;4. DNSSEC vs DoH/DoT&quot;">​</a></h4><table tabindex="0"><thead><tr><th>技术</th><th>解决什么问题</th><th>谁来用</th></tr></thead><tbody><tr><td>DoH / DoT</td><td>加密 DNS 传输，防窃听和篡改</td><td>客户端 → 递归 DNS 之间</td></tr><tr><td>DNSSEC</td><td>验证 DNS 数据的真实性，防篡改</td><td>整个 DNS 解析链路</td></tr></tbody></table><p>两者互补，不是替代关系。</p><hr><h3 id="其他-dns-相关概念" tabindex="-1">其他 DNS 相关概念 <a class="header-anchor" href="#其他-dns-相关概念" aria-label="Permalink to &quot;其他 DNS 相关概念&quot;">​</a></h3><p><strong>1. 任播（Anycast）</strong></p><ul><li>多个地方的服务器用同一个 IP 地址</li><li>用户请求时，网络路由会把他送到最近的那个节点</li><li>根 DNS 服务器、CDN 节点都用了任播技术</li></ul><p><strong>2. 智能 DNS / 智能解析</strong></p><ul><li>根据用户的 IP 地址、运营商、地理位置等，返回不同的解析结果</li><li>让用户访问最近的节点，提升速度</li><li>CDN 的核心技术之一</li></ul><p><strong>3. 泛解析（Wildcard DNS）</strong></p><ul><li><code>*.example.com</code> 匹配所有子域名</li><li>不用每个子域名都单独配一条记录</li><li>但也要小心，泛解析可能被利用做安全攻击</li></ul><p><strong>4. DNS 污染 / DNS 缓存投毒</strong></p><ul><li>往 DNS 缓存里注入假的记录</li><li>让缓存服务器返回错误的结果</li><li>DNSSEC 可以防范</li></ul><h2 id="追问-1-cdn-是如何通过-dns-实现智能调度的-cname-在其中起到什么作用" tabindex="-1">追问 1：CDN 是如何通过 DNS 实现智能调度的？CNAME 在其中起到什么作用？ <a class="header-anchor" href="#追问-1-cdn-是如何通过-dns-实现智能调度的-cname-在其中起到什么作用" aria-label="Permalink to &quot;追问 1：CDN 是如何通过 DNS 实现智能调度的？CNAME 在其中起到什么作用？&quot;">​</a></h2><h3 id="答" tabindex="-1">答 <a class="header-anchor" href="#答" aria-label="Permalink to &quot;答&quot;">​</a></h3><p>CDN（内容分发网络）的核心目标就是「让用户从最近的节点拿数据」，而 DNS 解析是实现这个目标的关键一环。</p><p><strong>CDN 的典型工作流程：</strong></p><ol><li>用户访问 <code>cdn.example.com/image.jpg</code></li><li>浏览器进行 DNS 解析</li><li>DNS 返回离用户最近的 CDN 节点 IP</li><li>用户向这个 CDN 节点请求资源</li><li>节点有缓存就直接返回，没有就回源站拉取再缓存</li></ol><p><strong>关键点：第 2 步 DNS 解析怎么知道用户在哪、该返回哪个节点？</strong></p><h3 id="cname-的作用" tabindex="-1">CNAME 的作用 <a class="header-anchor" href="#cname-的作用" aria-label="Permalink to &quot;CNAME 的作用&quot;">​</a></h3><p>CDN 一般用 <strong>CNAME 记录</strong> 来接入：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>www.example.com.  CNAME  www.example.com.cdnprovider.com.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>什么意思呢？</p><ul><li>你的域名 <code>www.example.com</code> 是一个别名（CNAME）</li><li>它真正指向的是 CDN 厂商的域名 <code>www.example.com.cdnprovider.com</code></li><li>DNS 解析时，先查到 CNAME，然后继续解析 CNAME 指向的域名</li><li>最终由 CDN 厂商的 DNS 服务器返回具体的节点 IP</li></ul><p><strong>为什么要用 CNAME？</strong></p><ol><li><strong>解耦</strong>：你不用关心 CDN 有哪些 IP，CDN 厂商自己管理节点 IP</li><li><strong>灵活调度</strong>：CDN 厂商可以随时调整节点 IP，不用你改 DNS</li><li><strong>智能解析</strong>：由 CDN 的 DNS 服务器来做智能调度，返回最优节点</li></ol><h3 id="智能-dns-调度的实现" tabindex="-1">智能 DNS 调度的实现 <a class="header-anchor" href="#智能-dns-调度的实现" aria-label="Permalink to &quot;智能 DNS 调度的实现&quot;">​</a></h3><p>CDN 厂商的 DNS 服务器（也叫「GSLB」——全局负载均衡）收到解析请求时，会根据这些信息判断该返回哪个节点：</p><p><strong>1. 用户地理位置（GeoDNS）</strong></p><ul><li>根据请求来源的 IP（实际上是 Local DNS 的 IP）判断用户所在地区</li><li>比如北京的用户返回北京节点，上海的用户返回上海节点</li><li>有精确的 IP 地理位置库，能精确到城市甚至区</li></ul><p><strong>2. 运营商</strong></p><ul><li>判断用户是电信、联通、移动还是其他运营商</li><li>返回同运营商的节点，避免跨运营商访问（跨运营商通常很慢）</li></ul><p><strong>3. 节点健康状态和负载</strong></p><ul><li>实时监控所有 CDN 节点的健康状态</li><li>如果某个节点挂了，就不再把用户调度过去</li><li>如果某个节点负载太高，就少调度一些用户过去</li></ul><p><strong>4. 节点距离 / 延迟</strong></p><ul><li>有些高级的 CDN 会实时探测各节点到用户的延迟</li><li>返回延迟最低的节点</li></ul><p><strong>5. 权重 / 比例</strong></p><ul><li>按一定比例把用户分到不同节点（灰度发布、流量迁移时用）</li></ul><h3 id="一个例子" tabindex="-1">一个例子 <a class="header-anchor" href="#一个例子" aria-label="Permalink to &quot;一个例子&quot;">​</a></h3><p>用户（北京联通）访问 <code>www.example.com</code>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 用户的浏览器查 www.example.com</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>2. 权威 DNS 返回 CNAME：www.example.com → www.example.cdn.com</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>3. 继续解析 www.example.cdn.com</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>4. CDN 的智能 DNS 收到请求：</span></span>
<span class="line"><span>   - 来源 IP 是「北京联通」的 DNS 服务器</span></span>
<span class="line"><span>   - 查询自己的节点列表：北京联通节点、上海联通节点、广州电信节点...</span></span>
<span class="line"><span>   - 选最近的「北京联通节点」</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>5. 返回北京联通节点的 IP：1.2.3.4</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>6. 用户直接访问 1.2.3.4 这个 CDN 节点</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><h3 id="调度精度的问题" tabindex="-1">调度精度的问题 <a class="header-anchor" href="#调度精度的问题" aria-label="Permalink to &quot;调度精度的问题&quot;">​</a></h3><p>智能 DNS 有一个<strong>天生的缺陷</strong>：它拿到的不是用户的真实 IP，而是用户 Local DNS 的 IP。</p><ul><li>如果用户用了运营商的 DNS，那 Local DNS 一般和用户在同一个地区、同一个运营商，调度还比较准</li><li>但如果用户用了公共 DNS（比如 8.8.8.8），那 Local DNS 可能在另一个城市甚至另一个国家，调度就不准了</li></ul><p>比如：</p><ul><li>一个北京的用户，用了 Google DNS（8.8.8.8）</li><li>CDN 的 DNS 看到请求来源是 Google DNS 的 IP（可能在上海或国外）</li><li>结果给这个用户调度到了上海节点，反而变慢了</li></ul><p><strong>怎么解决？——ECS（EDNS Client Subnet）</strong></p><p>ECS 是 DNS 协议的一个扩展，允许递归 DNS（Local DNS）在请求里带上用户的 IP 网段（不是完整 IP，保护隐私）。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DNS 请求里包含：用户 IP 段是 203.0.113.0/24（北京联通）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这样权威 DNS（CDN 的 DNS）就能拿到用户大致的地理位置，调度更准确。</p><ul><li>支持 ECS 的 DNS：Google DNS、Cloudflare DNS、国内大部分公共 DNS</li><li>不支持的话，调度精度就差一些</li></ul><h3 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h3><ul><li><strong>CNAME</strong>：把你的域名指向 CDN 厂商的域名，让 CDN 接管解析</li><li><strong>智能 DNS</strong>：CDN 厂商的 DNS 服务器根据用户位置、运营商、节点状态等，返回最优节点 IP</li><li><strong>ECS</strong>：解决公共 DNS 导致的调度不准问题，带上用户 IP 网段</li></ul><h2 id="追问-2-浏览器的-dns-缓存策略是怎样的-chrome-对-dns-有哪些优化" tabindex="-1">追问 2：浏览器的 DNS 缓存策略是怎样的？Chrome 对 DNS 有哪些优化？ <a class="header-anchor" href="#追问-2-浏览器的-dns-缓存策略是怎样的-chrome-对-dns-有哪些优化" aria-label="Permalink to &quot;追问 2：浏览器的 DNS 缓存策略是怎样的？Chrome 对 DNS 有哪些优化？&quot;">​</a></h2><h3 id="答-1" tabindex="-1">答 <a class="header-anchor" href="#答-1" aria-label="Permalink to &quot;答&quot;">​</a></h3><p>浏览器是 DNS 解析的「第一道关卡」，它的缓存策略和优化直接影响用户体验。</p><h3 id="chrome-的-dns-缓存" tabindex="-1">Chrome 的 DNS 缓存 <a class="header-anchor" href="#chrome-的-dns-缓存" aria-label="Permalink to &quot;Chrome 的 DNS 缓存&quot;">​</a></h3><p><strong>缓存位置：</strong></p><ul><li>浏览器进程维护一个 DNS 缓存表</li><li>Chrome 可以在 <code>chrome://net-internals/#dns</code> 查看和清空缓存</li></ul><p><strong>缓存时间：</strong></p><ul><li>不是固定的，受多个因素影响</li><li>一般遵循 DNS 记录的 TTL，但也有自己的上限和下限</li><li>Chrome 有个默认的缓存上限时间（大约几分钟），即使 TTL 很长也不会存太久</li><li>也有最小缓存时间，防止 TTL 太短导致频繁解析</li></ul><p><strong>缓存失效：</strong></p><ul><li>TTL 到期自动失效</li><li>浏览器关闭后缓存也会清掉（部分可能保留，但不持久化）</li><li>用户主动清除浏览数据</li></ul><h3 id="chrome-的-dns-优化手段" tabindex="-1">Chrome 的 DNS 优化手段 <a class="header-anchor" href="#chrome-的-dns-优化手段" aria-label="Permalink to &quot;Chrome 的 DNS 优化手段&quot;">​</a></h3><h4 id="_1-dns-预解析-dns-prefetch-1" tabindex="-1">1. DNS 预解析（dns-prefetch） <a class="header-anchor" href="#_1-dns-预解析-dns-prefetch-1" aria-label="Permalink to &quot;1. DNS 预解析（dns-prefetch）&quot;">​</a></h4><p>前面已经讲过，页面可以通过 <code>&lt;link rel=&quot;dns-prefetch&quot;&gt;</code> 提示浏览器提前解析。</p><p>但 Chrome 自己也会做一些自动预解析：</p><ul><li><strong>鼠标悬停预解析</strong>：当你把鼠标悬停在链接上时，Chrome 会提前解析那个链接的域名，等你点击时可能已经解析好了</li><li><strong>页面加载时预解析</strong>：Chrome 会扫描页面中的链接，提前解析可能会点击的域名</li><li><strong>地址栏预解析</strong>：你在地址栏输入时，Chrome 可能提前解析可能的目标域名</li></ul><p>这些都是浏览器自动做的，不需要网站配置。</p><h4 id="_2-dns-prefetch-控制" tabindex="-1">2. DNS Prefetch 控制 <a class="header-anchor" href="#_2-dns-prefetch-控制" aria-label="Permalink to &quot;2. DNS Prefetch 控制&quot;">​</a></h4><p>网站可以通过 HTTP 头或 meta 标签控制是否自动预解析：</p><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- 关闭自动 DNS 预解析（默认是开启的） --&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">meta</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> http-equiv</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;x-dns-prefetch-control&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> content</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;off&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- 手动指定要预解析的域名 --&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">link</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> rel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dns-prefetch&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;//cdn.example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>为什么要关闭？</p><ul><li>隐私考虑：你在 A 网站，浏览器却预解析了 B 网站的域名，B 网站能看到请求</li><li>但一般来说，开启利大于弊</li></ul><h4 id="_3-预连接-preconnect" tabindex="-1">3. 预连接（preconnect） <a class="header-anchor" href="#_3-预连接-preconnect" aria-label="Permalink to &quot;3. 预连接（preconnect）&quot;">​</a></h4><p>比 dns-prefetch 更进一步：</p><ul><li>不仅解析 DNS</li><li>还建立 TCP 连接</li><li>还做 TLS 握手（如果是 HTTPS）</li></ul><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">link</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> rel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;preconnect&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://api.example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>省了 DNS + TCP + TLS 一共 3 个 RTT（甚至更多）。</p><p>但注意：preconnect 成本比较高，不要用太多，一般最多 3-4 个。</p><h4 id="_4-预加载-preload" tabindex="-1">4. 预加载（preload） <a class="header-anchor" href="#_4-预加载-preload" aria-label="Permalink to &quot;4. 预加载（preload）&quot;">​</a></h4><p>比 preconnect 更进一步：</p><ul><li>不仅建立连接</li><li>还直接把资源下载下来</li></ul><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">link</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> rel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;preload&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://cdn.example.com/key.js&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;script&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>适合首屏关键资源，但要谨慎使用，避免浪费带宽。</p><h4 id="_5-chrome-的「预测服务」" tabindex="-1">5. Chrome 的「预测服务」 <a class="header-anchor" href="#_5-chrome-的「预测服务」" aria-label="Permalink to &quot;5. Chrome 的「预测服务」&quot;">​</a></h4><p>Chrome 有个叫「预测服务」（Prediction Service）的功能：</p><ul><li>根据你的浏览历史，预测你接下来可能访问什么网站</li><li>在你输入地址时，甚至在你打开浏览器时，就提前解析 DNS、建立连接、甚至预渲染页面</li><li>可以在 Chrome 设置里开关：「使用预测服务加快搜索和浏览速度」</li></ul><h4 id="_6-提前渲染-nostate-prefetch-prerender" tabindex="-1">6. 提前渲染（NoState Prefetch / Prerender） <a class="header-anchor" href="#_6-提前渲染-nostate-prefetch-prerender" aria-label="Permalink to &quot;6. 提前渲染（NoState Prefetch / Prerender）&quot;">​</a></h4><p>更极端的优化：</p><ul><li>不仅解析 DNS、建立连接</li><li>还提前把整个页面渲染好（在后台）</li><li>等用户真正访问时，几乎瞬间就能显示</li></ul><p>但这个消耗很大（CPU、内存、带宽），所以 Chrome 用得很谨慎，只在它非常确定你会访问时才用。</p><hr><h3 id="浏览器-dns-缓存的一些有趣细节" tabindex="-1">浏览器 DNS 缓存的一些有趣细节 <a class="header-anchor" href="#浏览器-dns-缓存的一些有趣细节" aria-label="Permalink to &quot;浏览器 DNS 缓存的一些有趣细节&quot;">​</a></h3><p><strong>1. 为什么有时刷新页面 DNS 缓存还在？</strong></p><ul><li>浏览器 DNS 缓存是进程级的，刷新页面不会清缓存</li><li>要清的话得用 <code>chrome://net-internals/#dns</code> 里的「Clear host cache」</li><li>或者重启浏览器</li></ul><p><strong>2. 为什么有时 DNS 改了，浏览器还访问旧 IP？</strong></p><ul><li>浏览器缓存没过期</li><li>操作系统缓存没过期</li><li>ISP DNS 缓存没过期</li><li>各级缓存都要等 TTL 过期才会更新</li><li>所以改 DNS 解析时，建议先把 TTL 改短，等旧缓存过期了再改记录</li></ul><p><strong>3. 一个页面有多个不同域名的资源，DNS 解析是并行的吗？</strong></p><ul><li>是的，浏览器会并行解析多个域名</li><li>但解析请求本身很快（缓存命中的话 0ms，不命中的话几十 ms）</li><li>真正耗时的是 TCP 连接和资源下载</li></ul><p><strong>4. HTTP/2 对 DNS 的影响？</strong></p><ul><li>HTTP/2 一个域名只需要一条连接（多路复用）</li><li>所以不需要像 HTTP/1.1 时代那样搞「域名分片」（sharding）来增加并发</li><li>域名少了，DNS 解析次数也少了，首屏更快</li></ul><h2 id="追问-3-dns-查询用的是-udp-还是-tcp-什么时候会用-tcp" tabindex="-1">追问 3：DNS 查询用的是 UDP 还是 TCP？什么时候会用 TCP？ <a class="header-anchor" href="#追问-3-dns-查询用的是-udp-还是-tcp-什么时候会用-tcp" aria-label="Permalink to &quot;追问 3：DNS 查询用的是 UDP 还是 TCP？什么时候会用 TCP？&quot;">​</a></h2><h3 id="答-2" tabindex="-1">答 <a class="header-anchor" href="#答-2" aria-label="Permalink to &quot;答&quot;">​</a></h3><p>这是一个经典面试题，答案是：<strong>主要用 UDP，但某些情况下也会用 TCP。</strong></p><h3 id="为什么-dns-主要用-udp" tabindex="-1">为什么 DNS 主要用 UDP？ <a class="header-anchor" href="#为什么-dns-主要用-udp" aria-label="Permalink to &quot;为什么 DNS 主要用 UDP？&quot;">​</a></h3><ol><li><strong>快</strong>：UDP 不需要三次握手，发一个请求包、回一个响应包就完事了</li><li><strong>简单</strong>：DNS 查询-响应模式很简单，一个请求对应一个响应</li><li><strong>开销小</strong>：UDP 头部只有 8 字节，TCP 头部 20 字节，连接建立还要额外开销</li><li><strong>幂等</strong>：DNS 查询是只读的，重复查询也没关系，丢了重发就行</li></ol><p>绝大多数 DNS 查询（比如查 A 记录、CNAME 记录）响应都很小，一个 UDP 包就能装下，所以用 UDP 就够了。</p><h3 id="什么时候-dns-会用-tcp" tabindex="-1">什么时候 DNS 会用 TCP？ <a class="header-anchor" href="#什么时候-dns-会用-tcp" aria-label="Permalink to &quot;什么时候 DNS 会用 TCP？&quot;">​</a></h3><h4 id="_1-响应大小超过-512-字节" tabindex="-1">1. 响应大小超过 512 字节 <a class="header-anchor" href="#_1-响应大小超过-512-字节" aria-label="Permalink to &quot;1. 响应大小超过 512 字节&quot;">​</a></h4><p>DNS 协议规定，UDP 模式下 DNS 响应大小不能超过 512 字节（历史限制）。如果响应超过这个大小，服务器会：</p><ul><li>只返回前 512 字节</li><li>并且设置响应中的 TC（Truncated，截断）位为 1</li><li>客户端收到后，知道响应被截断了，就会重新用 TCP 发起完整查询</li></ul><p><strong>什么时候响应会超过 512 字节？</strong></p><ul><li>域名有很多条 DNS 记录（比如很多 MX 记录、很多 NS 记录）</li><li>DNSSEC 签名（签名记录会大大增加响应大小）</li><li>大型机构的复杂 DNS 配置</li></ul><p><strong>注意：</strong> EDNS0（扩展 DNS）出现后，UDP 的最大大小可以超过 512 字节（最多可以到 4096 字节甚至更大），但为了兼容和避免 MTU 问题，很多情况下超过一定大小还是会切到 TCP。</p><h4 id="_2-区域传输-zone-transfer" tabindex="-1">2. 区域传输（Zone Transfer） <a class="header-anchor" href="#_2-区域传输-zone-transfer" aria-label="Permalink to &quot;2. 区域传输（Zone Transfer）&quot;">​</a></h4><p>主域名服务器和从域名服务器之间同步数据时用区域传输（AXFR / IXFR）。</p><ul><li>区域传输要传整个区域的所有 DNS 记录，数据量大</li><li>必须保证可靠传输，不能丢包</li><li>所以用 TCP</li></ul><h4 id="_3-dns-over-tls-dot-dns-over-https-doh" tabindex="-1">3. DNS over TLS (DoT) / DNS over HTTPS (DoH) <a class="header-anchor" href="#_3-dns-over-tls-dot-dns-over-https-doh" aria-label="Permalink to &quot;3. DNS over TLS (DoT) / DNS over HTTPS (DoH)&quot;">​</a></h4><p>加密 DNS：</p><ul><li>DoT 直接跑在 TLS 上，TLS 基于 TCP</li><li>DoH 跑在 HTTPS 上，HTTPS 基于 TCP（HTTP/3 除外，是 QUIC+UDP）</li></ul><h4 id="_4-其他特殊情况" tabindex="-1">4. 其他特殊情况 <a class="header-anchor" href="#_4-其他特殊情况" aria-label="Permalink to &quot;4. 其他特殊情况&quot;">​</a></h4><ul><li>有些防火墙或网络环境会拦截 UDP 53 端口，DNS 只能走 TCP</li><li>一些安全产品或特殊场景下的 DNS 查询</li></ul><hr><h3 id="为什么不是全部用-tcp" tabindex="-1">为什么不是全部用 TCP？ <a class="header-anchor" href="#为什么不是全部用-tcp" aria-label="Permalink to &quot;为什么不是全部用 TCP？&quot;">​</a></h3><p>既然 TCP 更可靠，为什么 DNS 不直接全用 TCP？</p><ol><li><p><strong>性能问题</strong>：TCP 三次握手要 1 个 RTT，对于 DNS 这种小包查询来说，开销太大了</p><ul><li>UDP：请求 → 响应，1 个 RTT</li><li>TCP：SYN → SYN+ACK → ACK + 请求 → 响应，要 2-3 个 RTT</li><li>DNS 解析本来就几十 ms，握手就要占一半甚至更多时间</li></ul></li><li><p><strong>服务器负载</strong>：TCP 连接要维护状态，服务器开销大</p><ul><li>UDP 是无连接的，服务器处理完就忘</li><li>如果所有 DNS 查询都用 TCP，根服务器和 TLD 服务器的连接数会爆炸</li></ul></li><li><p><strong>简单性</strong>：DNS 查询-响应模式非常适合 UDP，不需要 TCP 的复杂机制（流量控制、拥塞控制、顺序保证等）</p></li></ol><hr><h3 id="dns-端口" tabindex="-1">DNS 端口 <a class="header-anchor" href="#dns-端口" aria-label="Permalink to &quot;DNS 端口&quot;">​</a></h3><ul><li><strong>UDP 53</strong>：标准 DNS 查询端口（最常用）</li><li><strong>TCP 53</strong>：区域传输和大包查询</li><li><strong>TCP 853</strong>：DNS over TLS (DoT)</li><li><strong>TCP 443</strong>：DNS over HTTPS (DoH)</li><li><strong>UDP 443</strong>：DNS over QUIC（DoQ，比较新）</li></ul><hr><h3 id="一个常见误区" tabindex="-1">一个常见误区 <a class="header-anchor" href="#一个常见误区" aria-label="Permalink to &quot;一个常见误区&quot;">​</a></h3><p>很多人以为「DNS 就是 UDP」，但实际上现代 DNS 已经很复杂了：</p><ul><li>普通查询用 UDP</li><li>大包用 TCP（或 EDNS0 + UDP）</li><li>加密 DNS 用 TLS / HTTPS（TCP 或 QUIC）</li><li>区域传输用 TCP</li></ul><p>面试时回答「主要用 UDP，超过 512 字节或区域传输时用 TCP」，再补充一下 DoH/DoT，就比较完整了。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://hpbn.co/primer-on-dnssec/" target="_blank" rel="noreferrer">hpbn.co: Primer on DNS</a>：DNS 解析流程与优化</li><li><a href="https://www.rfc-editor.org/rfc/rfc1035" target="_blank" rel="noreferrer">RFC 1035: DNS</a>：域名解析基础协议</li><li><a href="https://www.w3.org/TR/resource-hints/#dns-prefetch" target="_blank" rel="noreferrer">W3C: Resource Hints — dns-prefetch</a>：dns-prefetch 资源提示</li></ul>`,253)])])}const D=i(t,[["render",n]]);export{u as __pageData,D as default};
